mapper.insert:
insert into batch.workflow_run ( tenant_id, workflow_definition_id, related_job_instance_id, biz_date, run_status, current_node_code, trace_id, dry_run ) values ( #{tenantId}, #{workflowDefinitionId}, #{relatedJobInstanceId}, #{bizDate}, #{runStatus}, #{currentNodeCode}, #{traceId},
#{dryRun} false
)

mapper.select:
select *
from batch.workflow_run
where tenant_id = #{tenantId}
  and id = #{id}

select *
from batch.workflow_run
where tenant_id = #{tenantId}
  and related_job_instance_id = #{relatedJobInstanceId}
order by id desc
limit 1

select *
from batch.workflow_run
where tenant_id = #{tenantId}

    and workflow_definition_id = #{workflowDefinitionId}


    and run_status = #{runStatus}

order by id desc

mapper.update:
update batch.workflow_run
set run_status = #{runStatus},
    current_node_code = #{currentNodeCode},
    finished_at = #{finishedAt},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}

    and run_status in
    #{s}

mapper.select:
select *
from batch.workflow_run
where run_status = 'RUNNING'
  and updated_at < #{stuckBefore}
order by updated_at asc, id asc
limit #{limit}

